import{_ as a,o as t,c as b,j as r,a as l,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const c=JSON.parse('{"title":"窥秘者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/神术/窥秘者.md","filePath":"4.资源分区/4.术法/神术/窥秘者.md"}'),i={name:"4.资源分区/4.术法/神术/窥秘者.md"};function n(o,e,s,d,_,C){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"窥秘者",tabindex:"-1"},[l("窥秘者 "),r("a",{class:"header-anchor",href:"#窥秘者","aria-label":'Permalink to "窥秘者"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),p('<h1 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h1><p>窥秘者</p><p>窥秘者</p><p>隐晦的途径暗藏在混乱的深渊之中，就如同地脉中蛮远晦暗的银矿，一经发掘就会引来灾难和不幸。但那讳莫如深的诱惑仍然在驱使着重赏之下蠢蠢欲动的人。远古诸位异神各自分据宇宙后，其走卒便应运诞生并为其永远效力。而低级走卒中不乏有幸运者得以窥探升格路径，侥幸踏入超凡入圣的边界，而在此边界内能侥幸存活者又是少之又少。</p><p>购买此系列资源的前提为强化神话生物血统或拥有神话典籍，本资源中提到的所有神话法术使用前提均为已拥有。</p><p>D级<br> 侥幸窥视<br> 前提：学识5</p><p>你获得了侥幸窥视升格途径的机会，本不属于你的禁忌知识因为某种原因开始被你缓慢的吸收，你那未经开化的大脑开始试图理解这些无法以任何方式理解的隐晦真相。<br> 你的意志力池将转化为一种新的名为【升格】的能量池。这个能量池的基础用法与恢复方式和意志力相同，并同时获得3个【升格】点数，这3个【升格】点数将分布在【升格】值的首位、1/2处、末位。当3个【升格】点数所在的位置的意志均被使用时，你视为开始升格仪式。进行一次DC为30的以智力+学识+对应专业的五面纬度延长检定，每一个维度检定一次。<br> 若检定成功，则视为升格成功，你在当前等级下达到无法超越的地步，你的共鸣能力将大幅上涨，所掌握的知识将变的更多且充满野心。<br> 若检定失败，则你不可避免的将陷入癫狂与苦痛之中，你需要重新开始此升格仪式，你的所有施法检定将必须先投掷一个十面自然骰。若出目高于5，则获得1点不可豁免的剧痛点数（最高不同时存在超过3点）；若出目低于5，则失去1点【升格】池中的意志。每次升格仪式失败后，下一次同等级升格仪式DC均下降5，获得的负面效果在升格仪式成功完成后移除。<br> 在你的升格仪式成功完成后，你的心智和力量将大幅度上涨。每当你在一场战斗中随机释放两个使用了动作的不同的C级神话法术后，下一次释放C级法术时将随机再释放一个使用迅捷动作及以下动作的同级的神话法术。</p><p>C级<br> 僭越边界<br> 在迈出第一步后，你已经成为了初阶升格者。血液中流淌着的对力量的渴望驱使着你越陷越深无法自拔。为了在升格之路上走的更远，你将不惜一切代价。<br> 前提：成为初阶升格者<br> 由于升格难度的提高，你将很难独自进行升格仪式，更多的是借助外力和道具。现在你可以在任意一场影片开始时向主神确认仪式开始，主神将会为你发布一个单人D级任务，完成这个任务将会获得仪式所需材料，并同时在影片中生成一个用于升格的仪式法阵。你可以在该场影片的任意时刻宣布升格仪式开始，进行一次DC为60的以智力+学识+对应专业的三面维度延长检定，每一个维度检定一次。若你拥有仪式所需材料，则DC降低5；若你寻找到法阵并以法阵进行仪式，则DC降低10；若二者均满足，则DC降低20。<br> 若检定成功，则你将成为高阶升格者，混乱而隐晦的知识在你的脑内变得清晰，你的能力开始接近伪神的地步，同时你的野心会驱使着你继续行进。<br> 若检定失败，则你需要重新开始升格仪式，且你的心智和功绩将开始崩塌，大量难以承受的反噬效果将在你调用能力时浮现。现在你每次释放一个神话法术时便需掷一次D6，根据出目决定承受的代价，当承受一个新的代价时，立即失去上一个代价带来的负面影响</p><ol><li>过度的扩张使你越加傲慢，对敌人的轻视也许会加速你的灭亡。你获得2点全检定上的士气减值、获得4点攻击检定上的盔甲减值、获得4点防御减值</li><li>经年累月的窥秘让你越加脆弱，疼痛使你无法集中精神进行冥想。你获得4点不可豁免，不会失去的剧痛点数</li><li>升格的苦痛正在逐渐吞噬你的灵巧和敏捷，让你变得更加笨拙迟缓。你获得40点移速减值（最低降低至1）、获得8点反射豁免检定上的减值</li><li>你的伤口无法愈合，这使得你更加难以承受伤害。你永久降低4点最大生命值上限，再获得8点强韧豁免检定上的减值</li><li>知识正在逐渐使你腐烂，你的残躯勉力支撑继续前行。你失去50点最大通用能量池上限，再永久失去4快疗点（前提是可失去，若无足够的快疗点用于失去，则按每1点快疗点=15通用能量池失去）</li><li>升格的渴望折磨着你的意志，它们使你陷入深重的苦恼之中。你永久降低4点最大意志池上限，再获得8点意志豁免检定上的减值</li></ol><p>每次升格仪式失败后，下一次同等级升格仪式DC均降低5，获得的负面效果在升格仪式成功完成后移除。<br> 在你的升格仪式成功完成后，你开始拥有足以扭曲现实的力量。当一场战斗中，你首次随机释放一个神话法术后，此后本场景中的每个随机释放的不同的C级神话法术都会再同时释放一个与此前释放的法术均不同的使用移动动作及以下动作的同等级的神话法术，分别进行检定，你的学识技能获得的表现加值上升2点。</p><p>B级<br> 登堂入殿<br> 你的血液翻涌，神智超然。神格开始在你的身上浮现，只需要再向前一步…只一步，你便可以真正的踏入神的境界之中。<br> 前提：成为高阶升格者<br> 升格越来越艰难，你已感到力不从心，但必须勉力支撑，事已至此，已没有回头路。<br> 现在你可以在任意一场影片开始时向主神确认仪式开始，主神将会为你发布一个单人C级任务，完成这个任务将会获得仪式所需材料，并同时在影片中生成一个用于升格的仪式法阵。你可以在该场影片的任意时刻宣布升格仪式开始，进行一次DC为120的以智力+学识+对应专业的二面维度延长检定，每一个维度检定一次。若你拥有仪式所需材料，则DC降低10；若你寻找到法阵并以法阵进行仪式，则DC降低20；若二者均满足，则DC降低40。<br> 若检定成功，则你升格为伪神，上下寰宇的知识已经被你掌握并玩弄于股掌之间，你将成为蛮远晦暗时代的开创者与奠基人，你的力量足以扭曲现实与真理，任何思想在你的面前都无所遁形。<br> 若检定失败，则你需要重新开始上一等级升格仪式并倒退至高阶升格者状态，功亏一篑使得你几乎毁灭，不得不保护自身而退出当前境界。<br> 在升格仪式失败时，你也可以选择放弃伪神以上的升格路径，直接进入伪神阶段，若如此做，则你失去学习A级及以上的神话法术的能力。<br> 在你的升格仪式成功完成或放弃继续升格的机会成为伪神后，你的神格将大幅度增加。同时，在影片中将开始出现你的信徒和信奉膜拜你的组织，随着你的神格的增加，你的信徒将越来越多。<br> 你开启五阶基因锁，这是一种异乎寻常的特殊潜能激发能力，少数升格者在晋升伪神且被逼入绝境时会进行基因及神格上的暴走。这个五阶基因锁将可以重复成功开启，在你希望抵御某次攻击时可以进行一次五阶基因锁检定，但不能获得任何开锁加值。成功打开五阶基因锁时可以无视那次攻击受到的伤害。</p><p>A级<br> 肉身成圣<br> 血肉只是无谓的阻碍，你的神格已经占据了身体的主导，除了旧日的支配者外，再无任何生灵敢在你的面前站立。<br> 前提：成为伪神<br> 去伪存真是极为艰难的一步，洗脱劣根，使神格主导身体，在苦痛与挣扎中升格，成为次级神明。<br> 你的五阶基因锁转变为六阶基因锁，伪神在通往次神的升格之路上将会受到多重险阻，少数伪神激发出了无尽的潜能并无法解释的大量获得神格。这个六阶基因锁将可以重复成功开启，在你希望抵御某次攻击时或希望主动对他人进行毁灭性打击时可以进行一次六阶基因锁检定，但不能获得任何开锁加值。若成功开锁，且意图为抵御某次攻击，则可以无视那次攻击受到的伤害，这是S级命运来源的无敌效果；每轮一次，若希望对他人进行毁灭性打击，则那次攻击骰获得【传奇】特性。成功开锁会降低至多15点当前仪式所需DC。<br> 现在你可以在任意一场影片开始时向主神确认仪式开始，主神将会为你发布一个单人B级任务，完成这个任务将会获得仪式所需材料，并同时在影片中生成一个用于升格的仪式法阵。你可以在该场影片的任意时刻宣布升格仪式开始，进行一次DC为240的以智力+学识+对应专业的一面维度延长检定，每一个维度检定一次。若你拥有仪式所需材料，则DC降低20；若你寻找到法阵并以法阵进行仪式，则DC降低40；若二者均满足，则DC降低80。<br> 当一个场景中，你随机释放了一个A级神话法术后，此后本场景中，你随机释放的所有A级神话法术都会额外在随机释放X个同级但与之前均不同的神话法术（X初始为1，每触发一次+1），分别进行检定。这些随机释放的神话法术中至多可以有一个以对自身最有利的形式释放。</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const h=a(i,[["render",n]]);export{c as __pageData,h as default};
